let raw = $json.action_input || $json.output || '';
if (!raw) throw new Error('No AI output');
if (typeof raw !== 'string') raw = JSON.stringify(raw);
raw = raw.trim();

let p = {};
try {
  let tmp = JSON.parse(raw);
  if (typeof tmp === 'string') tmp = JSON.parse(tmp);
  for (const [k,v] of Object.entries(tmp)) p[k.toLowerCase().trim()] = v;
} catch(e) {
  for (const l of raw.split('\n').map(s=>s.trim()).filter(s=>s.indexOf('=')>0)) {
    const i = l.indexOf('=');
    const k = l.slice(0,i).trim().toLowerCase();
    const v = l.slice(i+1).trim();
    if (k) p[k] = v;
  }
}

// Preserve raw AI output for debug
const _aiRaw = raw;

// mode
const validModes = ['incident','complaint','performance','reporting','unknown'];
const modeRaw = String(p.mode||'').toLowerCase().trim();
p.mode = validModes.includes(modeRaw) ? modeRaw : 'unknown';

// intent catalog
const validIntents = [
  'site_down_count','site_down_list','power_alarm_summary','tx_alarm_summary',
  'vip_down_sites','cascaded_sites_count','root_cause_summary','site_distance',
  'site_power_source','battery_health','ava_loss_estimate','traffic_loss_estimate',
  'last_site_actions','last_down_time','last_up_time','cell_status',
  'site_active_alarms','last_intervention','traffic_trend','application_traffic_trend',
  'kpi_summary','degradation_start_time','ava_trend','site_kpi_summary',
  'cell_kpi_summary','daily_traffic_total','daily_ava','vip_ava',
  'periodic_active_alarms','periodic_last_down_time','periodic_cascaded_sites',
  'site_details_summary','unknown'
];
const intentRaw = String(p.intent||'').toLowerCase().trim();
p.intent = validIntents.includes(intentRaw) ? intentRaw : 'unknown';

// geo_type
const validGeo = ['region','office','none'];
const geoRaw = String(p.geo_type||'').toLowerCase().trim();
p.geo_type = validGeo.includes(geoRaw) ? geoRaw : 'none';
p.region_input = String(p.region_input||'').trim();
p.office_input = String(p.office_input||'').trim();

// technology aliases → networktype
const techAliases = {lte:'4G',nr:'5G',umts:'3G',gsm:'2G','4g':'4G','3g':'3G','2g':'2G','5g':'5G'};
const techRaw = String(p.technology||p.networktype||'').trim();
const techNorm = techAliases[techRaw.toLowerCase()] || techRaw.toUpperCase() || '';
const validTech = ['2G','3G','4G','5G','GSM','UMTS','LTE','NR'];
p.technology = validTech.includes(techNorm) ? techNorm : techRaw;
p.networktype = p.technology;

// count_only
const co = String(p.count_only||'').toLowerCase();
p.count_only = co==='true'||co==='1';

// sitedownflag
const sd = String(p.sitedownflag||'').toLowerCase();
p.sitedownflag = sd.startsWith('yes') ? 'Yes' : '';

// sitepoweroff
const sp = String(p.sitepoweroff||'').toLowerCase();
p.sitepoweroff = sp.startsWith('yes') ? 'Yes' : '';

// isvip
const iv = String(p.isvip||'').toLowerCase();
p.isvip = iv.startsWith('yes') ? 'Yes' : '';

// category
p.category = String(p.category||'').toUpperCase().trim();
if (!['SITE_DOWN','POWER','CELL_DOWN'].includes(p.category)) p.category = '';

// severity
const sr = String(p.severity||'').toLowerCase().trim();
const validSev = ['critical','major','minor','warning','uncleared','cleared','active','open'];
p.severity = validSev.includes(sr) ? sr.charAt(0).toUpperCase()+sr.slice(1) : '';

// domain
p.domain = String(p.domain||'').trim();

// vendor, sitecode
p.vendor = String(p.vendor||'').trim();
p.sitecode = String(p.sitecode||'').trim();
p.acknowledged = String(p.acknowledged||'').trim();

// auto-set sitedownflag from intent
if (['site_down_count','site_down_list','vip_down_sites'].includes(p.intent) && !p.sitedownflag) p.sitedownflag = 'Yes';
// auto-set category from intent
if (!p.category && p.sitedownflag === 'Yes') p.category = 'SITE_DOWN';
if (!p.category && ['power_alarm_summary'].includes(p.intent)) p.category = 'POWER';

p._aiRaw = _aiRaw;

return [{ json: p }];

const j = $json;
const mode = String(j.mode||'').toLowerCase();
const cat = String(j.category||'').trim();
const domain = String(j.domain||'').trim();
const vendor = String(j.vendor||'').trim();
const networktype = String(j.networktype||'').trim();
const sitedownflag = String(j.sitedownflag||'').trim();
const severity = String(j.severity||'').trim();
const isvip = String(j.isvip||'').trim();
const sitepriority = String(j.sitepriority||'').trim();
const sitecode = String(j.sitecode||'').trim();

const hasAlarmContext = cat||domain||vendor||networktype||sitedownflag||severity||isvip||sitepriority||sitecode;
const operationalModes = ['incident','complaint','performance','reporting'];
const isOperational = operationalModes.includes(mode);
const isFreechat = !isOperational && !hasAlarmContext;

return [{ json: { ...j, _is_freechat: isFreechat } }];

const q = (($items('Parse Agent Output')[0]?.json?.user_question)||'').toLowerCase().trim();
const greetings = ['hi','hello','hey','howdy','hola','هاي','سلام','مرحبا','اهلا','أهلا','ازيك','هلو','يا هلا'];
const thanks = ['thanks','thank you','شكرا','شكراً','تسلم','مشكور'];
const isGreeting = greetings.some(g=>q===g||q.startsWith(g+' ')||q.startsWith(g+','));
const isThanks = thanks.some(t=>q.includes(t));
let reply;
if (isThanks) {
  reply = '😊 You are welcome! I am here to help.

Feel free to ask about alarms, sites, or network status.';
} else if (isGreeting) {
  reply = '👋 Hello! I am the NOC Operations AI Assistant for e& Egypt.

I support 4 operational modes:

📡 INCIDENT
  Site down counts/lists, Power alarms, TX alarms, VIP down, Cascaded sites
  Example: "How many site down in alex today?"

📞 COMPLAINT
  Last down time, Cell status, Active alarms on site, Last intervention
  Example: "Last down time for site ALX3480"

📈 PERFORMANCE  (routing active — data source coming in V3.6)
  Traffic trends, KPI summaries, AVA trend, Degradation start time
  Example: "Traffic trend for the last 7 days"

📊 REPORTING  (routing active — data source coming in V3.6)
  Daily traffic, Daily AVA, VIP AVA, Periodic summaries
  Example: "Daily AVA report for today"';
} else {
  reply = '🤖 I am specialized in telecom NOC operations.

Try asking:
  "How many site down in delta today?"
  "List VIP down sites in Cairo"
  "Power alarms in TANTA"
  "Last down time for site ALX3480"';
}
return [{ json: { reply, total: 0, debug: { type: 'free_chat', question: q, timestamp: new Date().toISOString() } } }];

const j = $input.first().json || {};
const geoType = String(j.geo_type||'none').toLowerCase();
const regionRaw = String(j.region_input||'').toLowerCase().trim();
const officeRaw = String(j.office_input||'').trim();

// Fuzzy corrections for region input
const fuzzy = {dleta:'delta',alx:'alex',alexndria:'alex',cai:'cairo',sinii:'sinai',uper:'upper egypt','upper':'upper egypt'};
const regionFixed = fuzzy[regionRaw] || regionRaw;

// Region → resolved location (pipe-string for API)
const geoMap = {
  'alex':'Alex','alexandria':'Alex','اسكندرية':'Alex','اسكندريه':'Alex',
  'cairo':'Cairo','القاهرة':'Cairo',
  'delta':'East Delta|West Delta','دلتا':'East Delta|West Delta',
  'upper egypt':'North Upper|South Upper','upper':'North Upper|South Upper','الصعيد':'North Upper|South Upper',
  'sinai':'Sinai','سينا':'Sinai','سيناء':'Sinai'
};

// Canonical FM office list for validation
const knownOffices = [
  'ALEX1','ALEX2','ALEX3','ALEX4','AlexCore',
  'Cairo','CairoCore','Downtown','Gesr El Suiz','Giza','Helwan','Mohandesen','OSS','Shorouk','Tagamo3',
  'DOMYAT','DYARBNEAGM','FAKOUS','MANSURA','ZAGAZIK',
  'DAMANHOUR','DELENGAT','KAFR ELSHEIKH','SHEBIN','TANTA',
  'ASSIUT','BANISUIEF','DEIR MAWAS','FAYOUM','MENYA','Maghagha',
  'ASWAN','Abu simple','EDFO','GERGA','LUXOR','QENA','SOHAG',
  'ABO REDIES','ARISH','HURGHADA','ISMAILIA','MARSA ALAM','NUWIBA','RASCEDER','SHARM','SUEZ','ZAFRANA'
];

let location_resolved = '';
let office_resolved = '';
let region_label = '';

if (geoType === 'region') {
  location_resolved = geoMap[regionFixed] || geoMap[regionRaw] || j.region_input || '';
  region_label = j.region_input || regionFixed;
  office_resolved = '';
} else if (geoType === 'office') {
  // Case-insensitive match against canonical list
  const match = knownOffices.find(o => o.toLowerCase() === officeRaw.toLowerCase());
  office_resolved = match || officeRaw;
  location_resolved = '';
  region_label = '';
}

return {
  ...j,
  geo_type: geoType,
  region_label,
  location_resolved,
  office_resolved
};

const j = $json;
const mode = j.mode || 'unknown';
const intent = j.intent || 'unknown';
const now = new Date().toISOString();

const reply = `⚠️ ${mode.charAt(0).toUpperCase()+mode.slice(1)} / ${intent} — Data Source Not Connected\n\nThis capability is part of the future plan.\nThe required ${mode} data source is not connected yet in V3.5.\n\nWhat the AI understood:\n  Mode   : ${mode}\n  Intent : ${intent}\n  Region : ${j.region_input||'—'}  Office: ${j.office_input||'—'}\n  Site   : ${j.sitecode||'—'}\n\nNo data was requested from any system.\nNo results were fabricated.\nThis will be connected in a future version.`;

const debug = {
  '1_user_request':      { question: j.user_question, debug_mode: j.debugMode||false, timestamp: now },
  '2_ai_raw_output':     { raw: j._aiRaw||'(not captured)' },
  '3_ai_interpretation': { mode, intent, category: j.category||'', geo_type: j.geo_type||'none', technology: j.technology||'', filters: { vendor: j.vendor, severity: j.severity, isvip: j.isvip, sitedownflag: j.sitedownflag, sitepoweroff: j.sitepoweroff, domain: j.domain } },
  '4_geography':         { region_input: j.region_input||'', office_input: j.office_input||'', geo_type: j.geo_type||'none', location_resolved: j.location_resolved||'', office_resolved: j.office_resolved||'' },
  '5_sql_mapping':       { skipped: true, reason: 'mode not connected in V3.5' },
  '6_time_range':        { skipped: true },
  '7_api_payload':       { skipped: true, reason: 'mode not connected in V3.5' },
  '8_api_response':      { skipped: true },
  '9_post_filter_dedup': { skipped: true },
  '10_count_logic':      { skipped: true },
  '11_final_reply':      { preview: reply.slice(0, 120) }
};

return [{ json: { reply, total: 0, debug } }];

const j = $json;
const cat = (j.category||'').toUpperCase();
const ven = j.vendor||'';
const tech = j.technology||'';
const domain = (j.domain||'').trim();
const nw = (j.networktype||'').trim();
const sdf = (j.sitedownflag||'').trim();
const isrootne = (j.isrootne||'').trim();

let sql;
if (cat === 'SITE_DOWN' || sdf === 'Yes') {
  sql = "SELECT '__DIRECT__' AS alarm_name";
} else if (cat === 'POWER') {
  let where = ["category = 'POWER'"];
  if (ven) where.push(`vendor = '${ven.replace(/'/g,"''")}' `);
  if (tech) where.push(`technology = '${tech.replace(/'/g,"''")}' `);
  sql = `SELECT alarm_name FROM ai_alarm_mappings WHERE ${where.join(' AND ')} ORDER BY alarm_name;`;
} else if (isrootne === 'Yes' || domain || nw || ven) {
  sql = "SELECT '__DIRECT__' AS alarm_name";
} else {
  sql = "SELECT '__DIRECT__' AS alarm_name";
}

return [{ json: { ...j, sql } }];

const ctx = $items('Build SQL')[0].json;
const q = (ctx.user_question||'').toLowerCase();
const now = new Date();
let s = new Date(now), e = new Date(now);
s.setHours(0,0,0,0); e.setHours(23,59,59,999);
if (q.includes('last 1 hour')||q.includes('last hour')){s=new Date(now.getTime()-3600000);e=new Date(now);}
else if (q.includes('last 6 hour')){s=new Date(now.getTime()-21600000);e=new Date(now);}
else if (q.includes('last 12 hour')){s=new Date(now.getTime()-43200000);e=new Date(now);}
else if (q.includes('last 24 hour')){s=new Date(now.getTime()-86400000);e=new Date(now);}
else if (q.includes('yesterday')){s=new Date(now);s.setDate(s.getDate()-1);s.setHours(0,0,0,0);e=new Date(now);e.setDate(e.getDate()-1);e.setHours(23,59,59,999);}
else if (q.includes('last 7 day')||q.includes('last week')){s=new Date(now.getTime()-604800000);e=new Date(now);}
else if (q.includes('last 2 day')){s=new Date(now.getTime()-172800000);e=new Date(now);}
else if (q.includes('last 3 day')){s=new Date(now.getTime()-259200000);e=new Date(now);}
const isHistorical = q.includes('last')||q.includes('yesterday')||q.includes('week');
const apiType = isHistorical ? 3 : 1;
const pad = n=>String(n).padStart(2,'0');
const fmt = d=>`${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
let sdf = ctx.sitedownflag||'';
let spo = ctx.sitepoweroff||'';
if (ctx.category==='SITE_DOWN'&&!sdf) sdf='Yes';
if (ctx.category==='POWER'&&!spo) spo='Yes';
const alevs = ['critical','major','minor','warning'];
const clevs = ['uncleared','cleared','active','open'];
const sr = (ctx.severity||'').toLowerCase().trim();
const stdSev = alevs.includes(sr) ? sr.charAt(0).toUpperCase()+sr.slice(1) : '';
const clSev = clevs.includes(sr) ? sr.charAt(0).toUpperCase()+sr.slice(1) : '';
return [{ json: {
  starttime: s.getTime(), endtime: e.getTime(),
  start_local: fmt(s), end_local: fmt(e),
  start: 0, limit: 1000, type: apiType,
  mode: ctx.mode, intent: ctx.intent, category: ctx.category,
  vendor: ctx.vendor, technology: ctx.technology, networktype: ctx.networktype,
  geo_type: ctx.geo_type, location_resolved: ctx.location_resolved,
  office_resolved: ctx.office_resolved, region_label: ctx.region_label,
  standardalarmseverity: stdSev, clearance_severity: clSev,
  sitedownflag: sdf, sitepoweroff: spo,
  acknowledged: ctx.acknowledged, isvip: ctx.isvip,
  domain: ctx.domain, sitepriority: ctx.sitepriority,
  isrootne: ctx.isrootne, sitecode: ctx.sitecode,
  count_only: ctx.count_only, user_question: ctx.user_question,
  debugMode: ctx.debugMode||false, _aiRaw: ctx._aiRaw||''
}}];

const t = $('Build Time Range').item.json;
const sqlItems = $items('Get Alarm Names From Mapping');
const allNames = sqlItems.map(i=>i.json.alarm_name).filter(Boolean);
const isDirectMode = allNames.length===0||allNames.includes('__DIRECT__');
const alarmNamesForApi = isDirectMode ? [] : allNames;

let payload = {
  start: t.start, limit: t.limit,
  starttime: t.starttime, endtime: t.endtime,
  type: t.type
};

function addIfValid(key, val) {
  if (val && String(val).toLowerCase() !== '(empty)') payload[key] = val;
}

// EXCLUSIVE geography — region OR office, never both
if (t.geo_type === 'region' && t.location_resolved) {
  addIfValid('location', t.location_resolved);
} else if (t.geo_type === 'office' && t.office_resolved) {
  addIfValid('city', t.office_resolved);
}

// Network / Equipment
addIfValid('vendor', t.vendor);
addIfValid('networktype', t.technology || t.networktype);

// Domain — TX/MW/RAN only, never Power
const domainClean = (t.domain||'').toUpperCase();
if (domainClean && domainClean !== 'POWER') addIfValid('domain', t.domain);

// Site flags — only in direct mode
if (isDirectMode) {
  addIfValid('sitedownflag', t.sitedownflag);
  addIfValid('sitepoweroff', t.sitepoweroff);
}

// Standard filters
addIfValid('isvip', t.isvip);
addIfValid('sitepriority', t.sitepriority);
addIfValid('isrootne', t.isrootne);
addIfValid('acknowledged', t.acknowledged);
addIfValid('sitecode', t.sitecode);
addIfValid('standardalarmseverity', t.standardalarmseverity);
addIfValid('severity', t.clearance_severity);

if (alarmNamesForApi.length > 0) payload['alarmname'] = alarmNamesForApi.join('|');

const isCountOnly = t.intent === 'alarm_count' || t.count_only === true || ['site_down_count','cascaded_sites_count','power_alarm_summary','tx_alarm_summary'].includes(t.intent) && t.count_only;

return [{ json: { payload, metadata: { count_only: isCountOnly, geo_type: t.geo_type, mode: t.mode, intent: t.intent, debugMode: t.debugMode, _aiRaw: t._aiRaw } } }];

const raw = $json;
const t = $items('Build Time Range')[0].json;

let records = Array.isArray(raw.result)  ? raw.result
            : Array.isArray(raw.data)    ? raw.data
            : Array.isArray(raw.records) ? raw.records
            : Array.isArray(raw.rows)    ? raw.rows : [];

const apiRawTotal = Number(raw.total||raw.count||raw.totalCount||raw.totalRecords||0);
const apiRealTotal = Math.max(apiRawTotal, records.length);

if (t.vendor) {
  records = records.filter(r=>(r.vendor||'').toLowerCase().includes(t.vendor.toLowerCase()));
}
const tech = t.technology || t.networktype || '';
if (tech) {
  records = records.filter(r=>(r.networktype||'').toLowerCase().includes(tech.toLowerCase()));
}
if (t.acknowledged) {
  records = records.filter(r=>String(r.acknowledged||''===String(t.acknowledged)));
}
if (t.sitecode) {
  records = records.filter(r=>(r.sitecode||'').toUpperCase()===t.sitecode.toUpperCase());
}

return [{ json: { total: apiRealTotal, records, _vendorFilter: t.vendor, _techFilter: tech, _preDedup: records.length } }];

const all = $input.all();
const t = $items('Build Time Range')[0].json;
const co = t.count_only === true;
const isSiteDown = (t.sitedownflag==='Yes'||t.category==='SITE_DOWN');
const isPower = (t.category==='POWER');
const isTX = (t.domain==='TX'||t.intent==='tx_alarm_summary');

function uk(r) {
  if (r.alarmid) return 'aid_'+r.alarmid;
  if (r.identifierfromprobe) return 'ifp_'+r.identifierfromprobe;
  if (r.identifier) return 'id_'+r.identifier;
  return 'cmp_'+[r.sitecode||'',r.alarmname||r.rawalarmname||'',r.firstoccurrence||'',r.networktype||'',r.city||r.location||''].join('_');
}

let apiTotal=0;
const seen=new Set();
const unique=[];

for (const item of all) {
  const rawT = Number(item.json.total||0);
  const recs = item.json.records||[];
  const itemTot = Math.max(rawT, recs.length);
  apiTotal += itemTot;
  for (const r of recs) {
    const k = uk(r);
    if (!seen.has(k)) { seen.add(k); unique.push(r); }
  }
}

const dedupedTotal = unique.length;
const finalTotal = co ? apiTotal : dedupedTotal;

const fl=[];
const loc = t.region_label||t.location_resolved||'';
if (loc)              fl.push('  📍 Location  : '+loc);
if (t.office_resolved)fl.push('  🏢 FM Office : '+t.office_resolved);
if (t.category)       fl.push('  📂 Category  : '+t.category);
if (isSiteDown)       fl.push('  🔴 Site Down : Yes');
if (isPower)          fl.push('  ⚡ Power Off : Yes');
if (isTX)             fl.push('  🌐 TX Domain : Yes');
if (t.isvip==='Yes')  fl.push('  ⭐ VIP Only  : Yes');
if (t.vendor)         fl.push('  🏭 Vendor    : '+t.vendor);
if (t.technology||t.networktype) fl.push('  📡 Network   : '+(t.technology||t.networktype));
if (t.sitepriority)  fl.push('  🎯 Priority  : '+t.sitepriority);
if (t.standardalarmseverity) fl.push('  🔔 Severity  : '+t.standardalarmseverity);
if (t.acknowledged)  fl.push('  ✅ Ack       : '+t.acknowledged);
if (t.sitecode)      fl.push('  🔍 Site Code : '+t.sitecode);
if (t.isrootne==='Yes') fl.push('  🌳 Root NE   : Yes');

const W=46;
const SEP='━'.repeat(W);
const hr='─'.repeat(W);

function buildNameGroups(records) {
  const g={};
  for (const r of records) {
    const k=r.alarmname||r.rawalarmname||'Unknown';
    const cnt=Number(r.tally||r.count||r.occurrences||1);
    g[k]=(g[k]||0)+cnt;
  }
  return Object.entries(g).sort((a,b)=>b[1]-a[1]);
}

function barLine(label,count,maxV) {
  const lb=label.length>28?label.slice(0,27)+'…':label.padEnd(28,' ');
  const cn=String(count).padStart(5,' ');
  const barLen=maxV>0?Math.round((count/maxV)*10):0;
  const bar='█'.repeat(barLen)+'░'.repeat(10-barLen);
  return `  ${lb} ${cn}  ${bar}`;
}

let reply=`📡 NOC Report — ${t.start_local}\n`;
reply+=`   Period  : ${t.start_local.slice(11)} → ${t.end_local.slice(11)}\n`;
reply+=SEP+'\n';
if (fl.length) {
  reply+='🔎 Filters:\n'+fl.join('\n')+'\n';
  reply+=hr+'\n';
}
reply+=`📊 TOTAL  : ${finalTotal} alarm${finalTotal!==1?'s':''}\n`;
reply+=hr+'\n';

if (unique.length>0) {
  const nameGroups=buildNameGroups(unique);
  const groupTotal=nameGroups.reduce((s,[,v])=>s+v,0);
  if (isSiteDown&&!co) {
    const top=Math.min(15,unique.length);
    reply+=`🏗️  Top ${top} Affected Sites:\n\n`;
    reply+='  #   Code           Tech   Vendor\n';
    reply+='  '+'─'.repeat(38)+'\n';
    for (let i=0;i<top;i++) {
      const r=unique[i];
      const n=String(i+1).padStart(2);
      const sc=(r.sitecode||r.sitename||'?').padEnd(14);
      const tc=(r.networktype||'?').padEnd(6);
      const vn=(r.vendor||'?');
      reply+=`  ${n}. ${sc} ${tc}  ${vn}\n`;
    }
    if (dedupedTotal>top) reply+=`\n  ... and ${dedupedTotal-top} more sites\n`;
  } else {
    const label=isPower?'⚡ By Alarm Type:':isTX?'🌐 By TX Alarm:':'📋 By Alarm Name:';
    reply+=label+'\n';
    const maxV=nameGroups[0]?.[1]||1;
    for (const [k,v] of nameGroups) reply+=barLine(k,v,maxV)+'\n';
    if (apiTotal>groupTotal) reply+=`\n  ℹ️  Based on ${unique.length} of ${apiTotal} records\n`;
  }
}

reply+=SEP;

return [{ json: { reply, total: finalTotal, api_total: apiTotal, deduped_total: dedupedTotal, _preDedup: all[0]?.json?._preDedup||0 } }];

const ai = $('Resolve Location').item.json||{};
const sql = $('Build SQL').item.json?.sql||'N/A';
const sqlRows = $items('Get Alarm Names From Mapping').map(i=>i.json);
const tr = $('Build Time Range').item.json||{};
const apiPayload = $('Build API Payload').item.json?.payload||{};
const meta = $('Build API Payload').item.json?.metadata||{};
const normItems = $('Normalize And Post Filter').all ? $('Normalize And Post Filter').all() : [];
const afterVendor = normItems[0]?.json?.records?.length||0;
